use parking_lot::RwLock;
use std::cmp::Ordering;
use std::collections::BinaryHeap;

const DIM: usize = 128;

pub struct VectorDB {
    ids: RwLock<Vec<u64>>,
    vectors: RwLock<Vec<f32>>, // flat layout: [v0(128), v1(128), ...]
}

#[derive(Debug)]
struct HeapItem {
    distance2: f32,
    id: u64,
}

impl PartialEq for HeapItem {
    fn eq(&self, other: &Self) -> bool {
        self.distance2 == other.distance2 && self.id == other.id
    }
}

impl Eq for HeapItem {}

impl PartialOrd for HeapItem {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        // Max-heap by distance, so largest distance is on top.
        self.distance2.partial_cmp(&other.distance2)
    }
}

impl Ord for HeapItem {
    fn cmp(&self, other: &Self) -> Ordering {
        self.partial_cmp(other).unwrap_or(Ordering::Equal)
    }
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            ids: RwLock::new(Vec::new()),
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if vector.len() != DIM {
            return;
        }

        let mut ids = self.ids.write();
        let mut vectors = self.vectors.write();

        ids.push(id);
        vectors.extend_from_slice(&vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut ids_guard = self.ids.write();
        let mut vecs_guard = self.vectors.write();

        let mut inserted = 0usize;
        ids_guard.reserve(vectors.len());
        vecs_guard.reserve(vectors.len() * DIM);

        for (id, vector) in vectors {
            if vector.len() != DIM {
                continue;
            }
            ids_guard.push(id);
            vecs_guard.extend_from_slice(&vector);
            inserted += 1;
        }

        inserted
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        if vector.len() != DIM || top_k == 0 {
            return Vec::new();
        }

        let ids = self.ids.read();
        let vecs = self.vectors.read();

        let n = ids.len();
        if n == 0 {
            return Vec::new();
        }

        let k = (top_k as usize).min(n);
        let mut heap: BinaryHeap<HeapItem> = BinaryHeap::with_capacity(k + 1);

        for i in 0..n {
            let start = i * DIM;
            let candidate = &vecs[start..start + DIM];
            let d2 = l2_distance_squared_128(vector, candidate);

            if heap.len() < k {
                heap.push(HeapItem {
                    distance2: d2,
                    id: ids[i],
                });
            } else if let Some(worst) = heap.peek() {
                if d2 < worst.distance2 {
                    heap.pop();
                    heap.push(HeapItem {
                        distance2: d2,
                        id: ids[i],
                    });
                }
            }
        }

        let mut out = Vec::with_capacity(heap.len());
        while let Some(item) = heap.pop() {
            out.push(SearchResult {
                id: item.id,
                distance: (item.distance2 as f64).sqrt(),
            });
        }

        out.sort_by(|a, b| {
            a.distance
                .partial_cmp(&b.distance)
                .unwrap_or(Ordering::Equal)
        });
        out
    }
}

#[inline]
fn l2_distance_squared_128(a: &[f32], b: &[f32]) -> f32 {
    debug_assert_eq!(a.len(), DIM);
    debug_assert_eq!(b.len(), DIM);

    #[cfg(target_arch = "x86_64")]
    {
        if std::arch::is_x86_feature_detected!("avx512f") {
            // SAFETY: Feature is checked at runtime; pointers are valid for DIM elements.
            return unsafe { l2_distance_squared_128_avx512(a, b) };
        }
    }

    let mut sum = 0.0f32;
    for i in 0..DIM {
        let d = a[i] - b[i];
        sum += d * d;
    }
    sum
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
unsafe fn l2_distance_squared_128_avx512(a: &[f32], b: &[f32]) -> f32 {
    use std::arch::x86_64::*;

    let mut acc = _mm512_setzero_ps();
    let pa = a.as_ptr();
    let pb = b.as_ptr();

    // 128 dims / 16 floats per register = 8 iterations
    for i in (0..DIM).step_by(16) {
        let va = _mm512_loadu_ps(pa.add(i));
        let vb = _mm512_loadu_ps(pb.add(i));
        let diff = _mm512_sub_ps(va, vb);
        acc = _mm512_fmadd_ps(diff, diff, acc);
    }

    _mm512_reduce_add_ps(acc)
}
