use parking_lot::RwLock;
use std::cmp::Ordering;
use std::collections::BinaryHeap;

const DIM: usize = 128;
const NLIST: usize = 256;
const NPROBE: usize = 24;
const TRAIN_SAMPLES: usize = 65_536;
const KMEANS_ITERS: usize = 6;

