    pub fn new() -> Self {
        Self {
            storage: RwLock::new(Storage {
                ids: Vec::new(),
                vectors: Vec::new(),
                index: None,
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if vector.len() != DIM {
            return;
        }
        let mut s = self.storage.write();
        s.ids.push(id);
        s.vectors.extend_from_slice(&vector);
        s.index = None;
    }

