        s.ids.reserve(vectors.len());
        s.vectors.reserve(vectors.len() * DIM);

        let mut inserted = 0usize;
        for (id, v) in vectors {
            if v.len() != DIM {
                continue;
            }
            s.ids.push(id);
            s.vectors.extend_from_slice(&v);
            inserted += 1;
        }
        if inserted > 0 {
            s.index = None;
        }
        inserted
    }

